mapper.select:
SELECT COUNT(*)
FROM STUDENT_CLASS
WHERE STUDENT_ID = #{studentId}
  AND CLASS_ID = #{classId}

mapper.delete:
DELETE FROM STUDENT_CLASS_TAG
WHERE STUDENT_CLASS_ID = #{studentClassId}
  AND EXISTS (
        SELECT 1
        FROM STUDENT_CLASS SC
        JOIN TEACHER_CLASS TC
          ON TC.CLASS_ID = SC.CLASS_ID
        WHERE SC.STUDENT_CLASS_ID = #{studentClassId}
          AND SC.END_DATE IS NULL
          AND TC.TEACHER_ID = #{teacherId}
          AND TC.STATUS = 'ACTIVE'
          AND TC.END_DATE IS NULL
  )

mapper.select:
SELECT COUNT(*)
FROM STUDENT_CLASS
WHERE STUDENT_ID = #{studentId}
  AND CLASS_ID = #{classId}
  AND END_DATE IS NULL

SELECT COUNT(*)
FROM STUDENT_CLASS
WHERE STUDENT_ID = #{studentId}
  AND CLASS_ID = #{classId}
  AND END_DATE IS NOT NULL
